prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskName1 ?taskName2 ?betweenName ?between
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5ee15f85aeb74d8d9e31df0e41fea6fe" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?t1 a bboExt:ChoreographyTask ;
      tai:belongsTo ?choreo ;
      bbo:name ?taskName1 .
  FILTER(CONTAINS(LCASE(STR(?taskName1)), LCASE("Estimate insurance cost")))

  ?t2 a bboExt:ChoreographyTask ;
      tai:belongsTo ?choreo ;
      bbo:name ?taskName2 .
  FILTER(CONTAINS(LCASE(STR(?taskName2)), LCASE("Send receipt")))

  # Find tasks that are reachable between t1 and t2 along outgoing sequence-flow paths.
  ?t1 ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?between .
  ?between a bboExt:ChoreographyTask ;
            tai:belongsTo ?choreo ;
            bbo:name ?betweenName .

  ?between ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?t2 .

  # Exclude endpoints.
  FILTER(?between != ?t1 && ?between != ?t2)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?type
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "5ee15f85aeb74d8d9e31df0e41fea6fe" ;
         tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?task a ?type ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(
    CONTAINS(LCASE(STR(?taskName)), LCASE("estimate insurance cost")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("send receipt"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?type ?norm ?orig ?orgId ?choreoCount ?taskCount ?anyName
WHERE {
  ?model a ?type ;
         tai:normalizedId ?norm .
  FILTER(?norm = "5ee15f85aeb74d8d9e31df0e41fea6fe")
  OPTIONAL { ?model tai:originalId ?orig . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    ?org tai:organizationId ?orgId .
  }
  OPTIONAL {
    ?defs tai:belongsTo ?model .
    ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  }
  OPTIONAL {
    ?defs2 tai:belongsTo ?model .
    ?choreo2 a bboExt:Choreography ; tai:belongsTo ?defs2 .
    OPTIONAL { ?task2 a bboExt:ChoreographyTask ; tai:belongsTo ?choreo2 . }
    OPTIONAL { ?task2 bbo:name ?anyName . }
  }
  BIND(1 as ?dummy)
}
LIMIT 25
